import { useParams, useNavigate } from "react-router-dom";
import "./styles/BookDetails.css";

function BookDetails() {
  const navigate = useNavigate();
  const { title, author, cover } = useParams();

  return (
    <div className="book-detail-page">
      <div className="detail-card">
        <img src={decodeURIComponent(cover)} alt={title} />

        <h2>{decodeURIComponent(title)}</h2>
        <p className="author">{decodeURIComponent(author)}</p>

        <p className="status avail">Available</p>

        <button className="borrow-btn">Borrow Book</button>

        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    </div>
  );
}

export default BookDetails;
